INSERT IGNORE INTO books (id, title, author, publisher, isbn, price, stock, cover, description, category, intro, audience, reason) VALUES
(1, 'JavaScript 高级程序设计', 'Nicholas C. Zakas', '人民邮电出版社', '9787115545381', 89.00, 38, '/assets/images/book-1.svg', '本书覆盖 JavaScript 核心语法、对象模型、DOM、事件、异步编程等重要内容，适合作为前端方向的重点推荐书籍。', '前端开发', '从语言基础到浏览器环境逐步展开，适合作为 JavaScript 系统学习资料。', '适合正在学习 Web 前端或需要补齐 JS 基础的读者。', '内容覆盖面广，能支撑书城项目中的技术类选品。'),
(2, 'CSS 权威指南', 'Eric A. Meyer', '中国电力出版社', '9787512387603', 76.00, 42, '/assets/images/book-2.svg', '系统梳理 CSS3 常见布局方式、选择器、盒模型与响应式技巧，是样式类图书的代表内容。', '前端开发', '围绕 CSS 选择器、布局、视觉格式化模型展开，帮助读者理解页面样式背后的规则。', '适合想深入理解样式体系和响应式布局的同学。', '与 React 页面实现结合紧密，适合作为在线书店的前端类图书。'),
(3, '人间失格', '太宰治', '作家出版社', '9787506380263', 32.00, 12, '/assets/images/book-3.svg', '经典文学作品能让电子书店页面不只局限于技术书籍，提升内容多样性和页面层次感。', '文学小说', '以第一人称叙事呈现人物内心世界，是现代文学中辨识度很高的作品。', '适合喜欢经典文学和人物心理描写的读者。', '文学类图书让列表更接近真实书店，而不是单一技术目录。'),
(4, '原则', '瑞·达利欧', '中信出版社', '9787508684031', 58.00, 25, '/assets/images/book-4.svg', '管理成长类图书可以让分类展示更完整，也更接近真实电商网站的商品结构。', '商业管理', '作者总结个人和组织管理中的决策方法，强调用原则处理复杂问题。', '适合关注自我管理、团队协作和商业思考的读者。', '补充管理成长类选品，让订单和购物车示例更丰富。'),
(5, '设计中的设计', '原研哉', '山东人民出版社', '9787209041065', 49.00, 30, '/assets/images/book-5.svg', '适合作为视觉设计类代表书籍，让整个电子书店的选品更完整，也与页面美观主题形成呼应。', '设计艺术', '从设计的本质、日常物品和信息传达角度讨论设计思维。', '适合视觉设计、产品设计和前端 UI 方向读者。', '能呼应本项目中的页面设计与用户体验要求。'),
(6, '活着', '余华', '作家出版社', '9787506365437', 36.00, 41, '/assets/images/book-6.svg', '作品知名度高、情感浓度强，适合用来丰富电子书店的文学类展示内容，让页面更真实。', '文学小说', '通过一个普通人的命运呈现时代变迁下的生命韧性。', '适合喜欢现实主义文学和中文小说的读者。', '经典畅销书有助于模拟真实在线书店的商品结构。');
